use std::fs::File;
use std::io::{self, BufReader, BufRead};

fn main() -> io::Result<()> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        println!("Usage: {} <file1> [file2] ...", args[0]);
        return Ok(());
    }

    let files_to_process = &args[1..];
    let mut results = String::new();

    for file_path in files_to_process {
        println!("Processing {}...", file_path);
        let file = File::open(file_path)?;
        let reader = BufReader::new(file);

        for line in reader.lines() {
            let line = line?;
            if !line.contains(":ERROR:") && !line.contains("DEBUG") && !line.contains("INFO") {
                if line.contains("192.168.1.") {
                    results.push_str(&format!("{}: {}n", file_path, line));
                }
            }
        }
    }

    println!("n--- Aggregated Results ---n{}", results);
    Ok(())
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read};

struct ConfigRecord {
    path: String,
    is_valid: bool,
    error: Option<String>,
}

fn load_and_validate(path: &str) -> Result<Vec<u8>, io::Error> {
    let mut file = File::open(path)?;
    let mut buffer = Vec::new();
    file.read_to_end(&mut buffer)?; 
    Ok(buffer)
}

fn process_config(record: &str) -> ConfigRecord {
    match load_and_validate(record) {
        Ok(_) => ConfigRecord { path: record.to_string(), is_valid: true, error: None },
        Err(e) => ConfigRecord { path: record.to_string(), is_valid: false, error: Some(e.to_string()) }
    }
}

fn main() -> Result<(), io::Error> {
    let file_paths = vec!["data/good_config.txt", "data/bad_file.bin", "data/another_good.cfg"];
    let mut results: HashMap<String, ConfigRecord> = HashMap::new();

    for path in file_paths {
        let record = process_config(path);
        results.insert(record.path.clone(), record);
    }

    println!("n--- Validation Summary ---");
    for (key, record) in results.iter() {
        if record.is_valid {
            println!("[SUCCESS] {}: File loaded and passed validation.", key); 
        } else {
            println!("[FAILED]  {}: Error: {:?}", key, record.error);
        }
    }

    Ok(())
}

use std::sync::{Mutex, Arc};

struct SharedCounter {
    value: Mutex<i32>,
}

impl SharedCounter {
    fn new() -> Self {
        SharedCounter { value: Mutex::new(0) }
    }

    fn increment(&self) -> i32 {
        let mut num = self.value.lock().unwrap();
        *num += 1;
        *num
    }
}

fn main() {
    let counter = Arc::new(SharedCounter::new());
    let mut handles = vec![];

    for i in 0..100 {
        let counter_clone = Arc::clone(&counter);
        let handle = std::thread::spawn(move || {
            let result = counter_clone.increment();
            println!("Thread {} finished, new value: {}", i, result);
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let final_value = counter.value.lock().unwrap().clone();
    println!("nFinal guaranteed value: {}", final_value);
}

use std::sync::{Arc, Mutex};
use std::thread;

struct SensorData {
    button_state: bool,
    temperature: f32,
}

fn main() {
    let shared_data = Arc::new(Mutex::new(SensorData {
        button_state: false,
        temperature: 20.0,
    }));

    let data_clone1 = Arc::clone(&shared_data);
    let handle1 = thread::spawn(move || {
        for i in 0..3 {
            thread::sleep(std::time::Duration::from_millis(100));
            { 
                let mut data = data_clone1.lock().unwrap();
                data.temperature += 1.5;
                println!("Reader Thread: Updated temperature to {:.1}", data.temperature);
            }
            thread::sleep(std::time::Duration::from_millis(100));
        }
    });

    let data_clone2 = Arc::clone(&shared_data);
    let handle2 = thread::spawn(move || {
        for _ in 0..3 {
            thread::sleep(std::time::Duration::from_millis(150));
            { 
                let mut data = data_clone2.lock().unwrap();
                data.button_state = !data.button_state;
                println!("Writer Thread: Button state toggled to {}", data.button_state);
            }
            thread::sleep(std::time::Duration::from_millis(150));
        }
    });

    handle1.join().unwrap();
    handle2.join().unwrap();

    let final_data = shared_data.lock().unwrap();
    println!("nFinal State: Button={}, Temperature={:.1}", 
        final_data.button_state, final_data.temperature);
}

use std::ops::Mul;

fn calculate_outer_product<T: Copy + Mul<Output = T> + std::fmt::Debug>(v1: &[T], v2: &[T]) -> Option<Vec<T>> { 
    if v1.is_empty() || v2.is_empty() {
        return None;
    }

    let result_dim = v1.len() * v2.len();
    let mut matrix = Vec::with_capacity(result_dim);

    for i in 0..v1.len() {
        for j in 0..v2.len() {
            let val = v1[i] * v2[j];
            matrix.push(val);
        }
    }

    Some(matrix)
}
